import { useEffect, useMemo, useState } from "react";
import { useSearchParams } from "react-router-dom";
import ProductCard from "../components/ProductCard";
import { categories, products } from "../data/products";

const maxProductPrice = Math.ceil(Math.max(...products.map((product) => product.price)));

function ProductListing() {
  const [searchParams] = useSearchParams();
  const initialCategory = searchParams.get("category");
  const searchQuery = (searchParams.get("q") || "").trim().toLowerCase();
  const [selectedCategories, setSelectedCategories] = useState(
    initialCategory ? [initialCategory] : []
  );
  const [priceLimit, setPriceLimit] = useState(maxProductPrice);
  const [sortBy, setSortBy] = useState("featured");

  useEffect(() => {
    if (initialCategory) {
      setSelectedCategories([initialCategory]);
      return;
    }
    setSelectedCategories([]);
  }, [initialCategory]);

  const filteredProducts = useMemo(() => {
    let visibleProducts = products.filter((product) => product.price <= priceLimit);

    if (selectedCategories.length > 0) {
      visibleProducts = visibleProducts.filter((product) =>
        selectedCategories.includes(product.category)
      );
    }

    if (searchQuery) {
      visibleProducts = visibleProducts.filter((product) =>
        [product.title, product.category, product.description]
          .join(" ")
          .toLowerCase()
          .includes(searchQuery)
      );
    }

    if (sortBy === "price-low") {
      return [...visibleProducts].sort((a, b) => a.price - b.price);
    }
    if (sortBy === "price-high") {
      return [...visibleProducts].sort((a, b) => b.price - a.price);
    }
    if (sortBy === "rating") {
      return [...visibleProducts].sort((a, b) => b.rating - a.rating);
    }
    return visibleProducts;
  }, [priceLimit, searchQuery, selectedCategories, sortBy]);

  const toggleCategory = (categoryLabel) => {
    setSelectedCategories((currentCategories) =>
      currentCategories.includes(categoryLabel)
        ? currentCategories.filter((label) => label !== categoryLabel)
        : [...currentCategories, categoryLabel]
    );
  };

  return (
    <div className="mx-auto max-w-7xl px-4 py-8 sm:px-6 lg:px-8">
      <div className="mb-6 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Product Listing</h1>
          <p className="mt-1 text-sm text-slate-500">
            Explore premium products with filters for category and price.
          </p>
          {searchQuery ? (
            <p className="mt-1 text-sm text-primary-600">
              Search results for: "{searchParams.get("q")}"
            </p>
          ) : null}
        </div>
      </div>

      <div className="grid gap-6 lg:grid-cols-[280px_1fr]">
        <aside className="h-fit rounded-xl border border-slate-100 bg-white p-5 shadow-md">
          <div>
            <h2 className="text-sm font-semibold uppercase tracking-wide text-slate-500">
              Categories
            </h2>
            <div className="mt-3 space-y-3">
              {categories.map((category) => (
                <label
                  className="flex cursor-pointer items-center justify-between text-sm text-slate-700"
                  key={category.id}
                >
                  <span>{category.label}</span>
                  <input
                    checked={selectedCategories.includes(category.label)}
                    className="h-4 w-4 rounded border-slate-300 text-primary-600 focus:ring-primary-500"
                    onChange={() => toggleCategory(category.label)}
                    type="checkbox"
                  />
                </label>
              ))}
            </div>
          </div>

          <div className="mt-8">
            <h2 className="text-sm font-semibold uppercase tracking-wide text-slate-500">
              Price
            </h2>
            <input
              className="mt-4 w-full accent-primary-600"
              max={maxProductPrice}
              min={20}
              onChange={(event) => setPriceLimit(Number(event.target.value))}
              type="range"
              value={priceLimit}
            />
            <p className="mt-2 text-sm font-medium text-slate-700">
              Up to ${priceLimit.toFixed(2)}
            </p>
          </div>
        </aside>

        <section>
          <div className="mb-5 flex flex-wrap items-center justify-between gap-3 rounded-xl border border-slate-100 bg-white p-4 shadow-md">
            <p className="text-sm text-slate-500">
              Showing {filteredProducts.length} products
            </p>
            <select
              className="rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm text-slate-700 focus:border-primary-500 focus:outline-none"
              onChange={(event) => setSortBy(event.target.value)}
              value={sortBy}
            >
              <option value="featured">Sort: Featured</option>
              <option value="rating">Sort: Top Rated</option>
              <option value="price-low">Sort: Price Low to High</option>
              <option value="price-high">Sort: Price High to Low</option>
            </select>
          </div>

          <div className="grid gap-5 sm:grid-cols-2 xl:grid-cols-3 2xl:grid-cols-4">
            {filteredProducts.map((product) => (
              <ProductCard key={product.id} product={product} />
            ))}
          </div>
        </section>
      </div>
    </div>
  );
}

export default ProductListing;
